def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            base_priority = (ratio ** 5) - np.sqrt(capacity) * 0.7
            cascade = 1.0
            for x in range(1, int(capacity) + 3):
                if x % 5 == 0:
                    cascade *= np.log(x + ratio + epsilon)
                elif x % 2 == 0:
                    cascade += np.sin(ratio * x) / (x + epsilon)
                else:
                    cascade -= np.cos(capacity / (x + epsilon))
                if cascade < 0:
                    cascade = abs(cascade)*0.5
            if capacity > item:
                cascade *= np.exp(-ratio)
            priority = base_priority * cascade
            if capacity % 4 == 0:
                for rep in range(3):
                    priority += np.sum([np.tanh((item+i) / (capacity+rep+1)) for i in range(rep+1)])
            else:
                priority /= (np.log(capacity + ratio + epsilon) + 1)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity+1)
            cumulative = 0
            for y in range(1, int(item)+int(capacity)+1):
                if y % 4 == 0:
                    cumulative += (y / (capacity + 2)) ** 3
                else:
                    cumulative -= (np.log(y+ratio+epsilon) / (item + epsilon))
                if cumulative < -50:
                    cumulative = -50
                if cumulative > 50:
                    cumulative = 50
            priority += np.tanh(cumulative)
            priority = max(priority, 1e-5)
        elif 0.5 < ratio <= 2:
            priority = np.log(1 + ratio * capacity + epsilon)
            factor = 1.0
            for z in range(1, 8):
                partial = np.exp(-z / (ratio + epsilon)) * (capacity % (z + 1) + 1)
                if z % 3 == 0:
                    factor *= partial
                else:
                    factor += partial / (z + 0.5)
                if factor > 100:
                    factor /= 10
                elif factor < 0.1:
                    factor *= 10
            priority *= factor
        elif 0.1 < ratio <= 0.5:
            priority = (1 / (1 - ratio + epsilon)) + np.sin(capacity * ratio)
            series_sum = 0
            for n in range(1, int(capacity*ratio)+1):
                term = ((-1)**n) * (ratio**n) / (n + epsilon)
                series_sum += term
                if abs(term) < 1e-5:
                    break
            priority += abs(series_sum)
            if int(capacity) % 2 == 0:
                priority *= 1.07
            else:
                priority /= 1.02
        else:
            alt_sum = 0
            for w in range(1, int(capacity)+2):
                val = (np.sin(ratio*w) + np.cos(capacity / (w + epsilon))) / (w + epsilon)
                if w % 2 == 0:
                    alt_sum += val
                else:
                    alt_sum -= val
                if abs(alt_sum) > 1000:
                    alt_sum /= 10
            priority = abs(alt_sum) + 0.3 * np.sqrt(item + capacity)
            if priority > 100:
                priority = np.log(priority + 1) * 20
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            fluctuator = 1
            for p in range(1, int(diff)+2):
                fluctuator *= np.tanh((p + capacity) / (item + epsilon))
                if p % 2 == 0:
                    penalty += np.sqrt(p + fluctuator)
                else:
                    penalty -= (p * fluctuator * 0.05)
                if penalty < 0:
                    penalty = 0
            penalty = max(penalty, 0)
            priority += penalty
        if priority < 0:
            priority = abs(priority) + 1
        priorities[i] = priority
    max_prio = np.max(priorities[np.isfinite(priorities)])
    min_prio = np.min(priorities[np.isfinite(priorities)])
    if max_prio > min_prio:
        priorities = (priorities - min_prio) / (max_prio - min_prio)
    else:
        priorities.fill(0)
    return priorities
